    letters = test.split()

    # Create a dictionary to count occurrences of each letter
    letter_count = {}

    for letter in letters:
        if letter in letter_count:
            letter_count[letter] += 1
        else:
            letter_count[letter] = 1

    # Find the maximum occurrence count
    max_count = max(letter_count.values(), default=0)

    # Return all letters with the maximum occurrence count
    return {letter: count for letter, count in letter_count.items() if count == max_count}

