    if not filename:
        return abort(400, description="No filename provided")

    if not is_valid_filename(filename):
        return abort(400, description="Invalid filename")

    # Use a relative path to avoid issues with current working directory
    uploads_dir = os.path.join(os.getcwd(), "uploads")

