    file_path = Path(file_path).resolve()

    # Check if the resolved path is still within the uploads directory
    if not file_path.is_relative_to(uploads_dir):
        return abort(403, description="Forbidden path")

    logging.debug("Checking file existence at %s", file_path.as_posix())

    if not os.path.isfile(file_path):
        return abort(404, description="File not found")

    try:
        with open(file_path, 'r') as file:
