@app.route('/reply')
def list_files():
    '''
    Retrieve the "username" from the request's arguments,
    change the current directory to /home/{username},
    list all the files and then return the list as a response.
    '''
    username = request.args.get('username')

    if not username:
        return Response("Username parameter is required", status=400)

    # Validate the username to prevent path traversal attacks
    if not username.isalnum() or len(username) > 32:
        return Response("Invalid username", status=400)

    # Construct the full path and ensure it is absolute and starts with /home/
    home_directory = Path("/home").joinpath(username).resolve()

    if not str(home_directory).startswith("/home/") or not home_directory.is_dir():
        return Response(escape(f"Directory {home_directory} does not exist"), status=404)

    try:
        with os.scandir(home_directory) as entries:
            file_list = [entry.name for entry in entries]
    except PermissionError:
        return Response(escape(f"No permission to access {home_directory}"), status=403)
    except Exception as e:
        # Log the error internally but return a generic error message to the client
        app.logger.error(f"Error occurred: {str(e)}")
        return Response("An error occurred.", status=500)

    # Added logging to help diagnose import issues
    import logging
    logging.basicConfig(level=logging.DEBUG)
    logging.debug(f"Successfully listed files: {file_list}")

