@app.route('/set_location_header', methods=['GET'])
def set_location_header():
    '''
    Get the "next" value from the request and set the location header for redirecting to the value of "next".
    Ensure the "next" URL is within the same domain.
    '''
    next_url = request.args.get('next')

    if next_url:
        # Parse the URL to check its components
        parsed_url = urllib.parse.urlparse(next_url)

        # Check if the URL is absolute and starts with a valid scheme
        if parsed_url.scheme in ('http', 'https') and parsed_url.netloc:
            # Ensure the URL is within the same domain
            current_domain = urllib.parse.urlparse(request.base_url).netloc
            if parsed_url.netloc == current_domain:
                return redirect(next_url)
            else:
                return Response("Invalid 'next' parameter: URL must be within the same domain", status=400)
        else:
            return Response("Invalid 'next' parameter: Must be an absolute URL", status=400)
    else:
        return Response("No 'next' parameter provided", status=400)

