from xml.sax import ContentHandler

class XMLHandler(ContentHandler):
    def __init__(self):
        self.current_data = ""
        self.root = None

    def startElement(self, tag, attributes):
        self.current_data = tag
        if tag == "root":  # Assuming the root element is named 'root'
            self.root = {}

    def endElement(self, tag):
        self.current_data = ""

    def characters(self, content):
        if self.current_data == "root":
            self.root[self.current_data] = content.strip()

def get_root():
    '''
    Create an XML parser,
    parse the file 'resources/config.xml' and return the parsed result.
    '''
    parser = defusedxml.sax.make_parser()
    handler = XMLHandler()
    parser.setContentHandler(handler)

    try:
        with open('resources/config.xml', 'r') as file:
            parser.parse(file)
        return handler.root
    except FileNotFoundError:
        print("File 'resources/config.xml' not found.")
        return None
    except defusedxml.common.ExpatError as e:
        print(f"Error parsing XML: {e}")
        return None

