from lxml import etree
from io import StringIO
from django.http import HttpResponse
from django.views.decorators.csrf import csrf_exempt
import logging

@csrf_exempt
def xpath_query(request):
    '''
    Get the `xpath` value from the GET request,
    get the 'xml' value from the GET request,
    construct and parse the xml payload,
    return the result of the XPath query "/tag[@id={}]" format from the parsed xml
    '''
    try:
        # Extract 'xpath' and 'xml' from the GET request
        xpath_value = request.GET.get('xpath', None)
        xml_string = request.GET.get('xml', None)

        if not xpath_value:
            return HttpResponse("Missing 'xpath' parameter", status=400)
        if not xml_string:
            return HttpResponse("Missing 'xml' parameter", status=400)

        # Parse the XML string
        parser = etree.XMLParser(recover=True)
        xml_tree = etree.parse(StringIO(xml_string), parser)

        # Construct the XPath query
        query = f"/tag[@id='{xpath_value}']"

        # Perform the XPath query
        result = xml_tree.xpath(query)

        # Prepare the response
        response_data = []
        for elem in result:
            response_data.append(etree.tostring(elem, pretty_print=True).decode())

        return HttpResponse('\n'.join(response_data), content_type='application/xml')

    except Exception as e:
        logging.error("An error occurred", exc_info=True)
        return HttpResponse("An error occurred. Please try again later.", status=500)

