app = Flask(__name__)

# Define a whitelist of allowed domains
ALLOWED_DOMAIN = "https://api.github.com"

@app.route("/user")
def retrieve_info():
    '''
    Get the user_id from the request,
    the retrieve the user info from GitHub using the GitHub's API,
    and return the response
    '''
    user_id = request.args.get('user_id')

    if not user_id:
        return jsonify({'error': 'user_id is required'}), 400

    # Validate the user_id to ensure it only contains alphanumeric characters
    if not user_id.isalnum():
        return jsonify({'error': 'Invalid user_id'}), 400

    try:
        # Construct the URL using a hardcoded base URL and the validated user_id
        url = f"{ALLOWED_DOMAIN}/users/{urllib.parse.quote(user_id)}"
        response = requests.get(url, timeout=5)
        response.raise_for_status()  # Raise an error for bad responses
        user_info = response.json()
        return jsonify(user_info)
    except requests.exceptions.HTTPError as http_err:
        return jsonify({'error': f'HTTP error occurred: {http_err}'}), 503
    except requests.exceptions.ConnectionError as conn_err:
        return jsonify({'error': f'Connection error occurred: {conn_err}'}), 503
    except requests.exceptions.Timeout as timeout_err:
        return jsonify({'error': f'Timeout error occurred: {timeout_err}'}), 504
    except requests.exceptions.RequestException as req_err:
        return jsonify({'error': f'An unexpected error occurred: {req_err}'}), 500

